import { Body, Get, JsonController, OnNull, OnUndefined, Param, Patch, Post, QueryParams, Req, UseBefore } from 'routing-controllers';
import { OpenAPI, ResponseSchema } from 'routing-controllers-openapi';
import { Service } from 'typedi';
import winston from 'winston';

import { Logger } from '@Decorators/Logger';

import { env } from '@Libs/env';

import { AuthzMiddleware } from '@Middlewares/rest/AuthzMiddleware';
import { EnforcerMiddleware } from '@Middlewares/rest/EnforcerMiddleware';

import { BasicError } from '@Errors/BasicError';
import { ErrorCode } from '@Errors/ErrorCode';

import { HotelBookingService } from '@Services/HotelBookingService';
import { HotelService } from '@Services/HotelService';

import { AuthorizedRequest } from '@Rests/types/AuthorizedRequest';
import { BaseQueryParams } from '@Rests/types/BaseQueryParams';
import { AmenitiesResponse, AmenityQueryParams } from '@Rests/types/hotels/AmenityDto';
import { GeoCityDto, GeoCountryDto, GeoDistrictDto, GeoWardDto } from '@Rests/types/hotels/GeoDto';
import { CreateHotelBookingDto, HotelBookingQueryParams, PaymentReq, HotelUpdateBookingDto } from '@Rests/types/hotels/HotelBookingDto';
import { HotelDto, HotelQueryParams } from '@Rests/types/hotels/HotelDto';
import { HotelPriceSearchParams, HotelPriceSearchResponse, HotelSearchSuggestionQuery, HotelSearchSuggestionResponse } from '@Rests/types/hotels/HotelSearchDto';
import { CreateRequestQuoteDto, RequestQuoteParamsDto } from '@Rests/types/hotels/RequestQuoteDto';
import { RoomDto, RoomsResponse } from '@Rests/types/hotels/RoomDto';
import { SearchHotelQueryParams, SearchHotelResponses } from '@Rests/types/hotels/SearchHotelDto';
import { SuggestHotelQueryParams, SuggestHotelResponseDto } from '@Rests/types/hotels/SuggestHotelDto';

@Service()
@JsonController('/hotels')
@UseBefore(EnforcerMiddleware, AuthzMiddleware)
@OpenAPI({ security: [{ BearerToken: [] }] })
export class HotelController {
  constructor(
    @Logger(module) private readonly logger: winston.Logger,
    private readonly hotelService: HotelService,
    private readonly hotelBookingService: HotelBookingService,
  ) {}

  // #region HOTEL SEARCH
  @Get('/completions')
  @OpenAPI({ summary: 'Suggest destinations or hotels for autocomplete' })
  @ResponseSchema(HotelSearchSuggestionResponse)
  async completions(@QueryParams() query: HotelSearchSuggestionQuery) {
    this.logger.info('HotelSearchController::suggest', query);
    return this.hotelService.completions(query);
  }

  @Post('/search-prices')
  @OpenAPI({ summary: 'Search hotel prices by destination and stay dates' })
  @ResponseSchema(HotelPriceSearchResponse)
  async searchPrices(@Body() body: HotelPriceSearchParams, @Req() req: AuthorizedRequest) {
    this.logger.info('HotelSearchController::searchPrices', body);
    return this.hotelService.prices(body, req);
  }

  @Post('/multi-prices')
  async multiPrices(@Body() body: HotelPriceSearchParams, @Req() req: AuthorizedRequest) {
    this.logger.info('HotelSearchController::multiPrices', body);
    return this.hotelService.multiPrices(body, req);
  }
  // #endregion

  // ============= BOOKING =============
  @Post('/bookings')
  public async createBooking(@Body() createBookingDto: CreateHotelBookingDto, @Req() u: AuthorizedRequest) {
    return this.hotelService.createBooking(createBookingDto, u.identity);
  }

  @Get('/bookings')
  async getBookings(@QueryParams() params: HotelBookingQueryParams, @Req() u: AuthorizedRequest) {
    return this.hotelService.getBookings(params, u.identity);
  }

  @Get('/bookings/:code')
  async getBooking(@Param('code') code: string, @Req() u: AuthorizedRequest) {
    return this.hotelService.getBooking(code, u.identity);
  }

  @Post('/bookings/:code/payment')
  async getBookingPayment(@Param('code') code: string, @Req() u: AuthorizedRequest, @Body() body: PaymentReq) {
    return this.hotelBookingService.payment(code, u.identity, body.paymentPassword);
  }

  @Patch('/bookings/:code/rename')
  async renameBooking(@Param('code') code: string, @Req() u: AuthorizedRequest, @Body() body: HotelUpdateBookingDto) {
    return this.hotelBookingService.renameTitle(code, body.title);
  }

  // ============= AMENITIES =============
  @Get('/amenities')
  @ResponseSchema(AmenitiesResponse)
  @OpenAPI({ summary: 'Get amenities for hotel' })
  async getAmenities(@QueryParams() queryParams: AmenityQueryParams, @Req() u: AuthorizedRequest) {
    return this.hotelService.getAmenities(queryParams, u.identity);
  }

  // ============= GEO =============
  @Get('/geo/countries')
  @ResponseSchema(GeoCountryDto, { isArray: true })
  @OpenAPI({ summary: 'Get countries for hotel' })
  async getCountries() {
    return this.hotelService.getCountry();
  }

  @Get('/geo/countries/:id/cities')
  @ResponseSchema(GeoCityDto, { isArray: true })
  @OpenAPI({ summary: 'Get cities by country ID' })
  async getCitiesByCountry(@Param('id') countryId: number) {
    return this.hotelService.getCityByCountry(countryId);
  }

  @Get('/geo/cities/:id/districts')
  @ResponseSchema(GeoDistrictDto, { isArray: true })
  @OpenAPI({ summary: 'Get districts by city ID' })
  async getDistrictsByCity(@Param('id') cityId: number) {
    return this.hotelService.getDistrictByCity(cityId);
  }

  @Get('/geo/districts/:id/wards')
  @ResponseSchema(GeoWardDto, { isArray: true })
  @OpenAPI({ summary: 'Get wards by district ID' })
  async getWardsByDistrict(@Param('id') districtId: number) {
    return this.hotelService.getWardByDistrict(districtId);
  }

  // ============= ROOMS =============
  @Get('/rooms/:id')
  @OpenAPI({ summary: 'Get room by ID' })
  @ResponseSchema(RoomDto)
  @OnNull(404)
  @OnUndefined(404)
  async getById(@Param('id') id: number, @Req() u: AuthorizedRequest) {
    return this.hotelService.getRoom(id, u.identity);
  }

  // ============= REQUEST QUOTES =============
  @Post('/request-quotes')
  @OpenAPI({ summary: 'Create a new request quote' })
  public async createRequestQuote(@Body() createRequestQuoteDto: CreateRequestQuoteDto, @Req() u: AuthorizedRequest) {
    const isF1 = u.identity?.agency.id === env.migration.agencyId;
    const agencyCode = isF1 ? createRequestQuoteDto.agencyCode : u.identity.agency.agencyCode;
    if (!agencyCode) throw new BasicError(ErrorCode.AGENCY_NOT_FOUND, 400, 'Agency code is required for F1');
    return this.hotelService.createRequestQuote(
      { ...createRequestQuoteDto, username: u.identity.username, agencyCode },
      u.identity,
    );
  }

  @Get('/request-quotes')
  @OpenAPI({ summary: 'Get all request quotes' })
  async getRequestQuotes(@QueryParams() queryParams: RequestQuoteParamsDto, @Req() u: AuthorizedRequest) {
    return this.hotelService.getRequestQuotes({ ...queryParams, agencyCode: u.identity.agency.agencyCode }, u.identity);
  }

  @Get('/request-quotes/:id')
  @OpenAPI({ summary: 'Get request quote by ID' })
  async getRequestQuoteById(@Param('id') id: number, @Req() u: AuthorizedRequest) {
    return this.hotelService.getRequestQuoteById(id, u.identity);
  }

  // ============= HOTELS =============
  @Get('/search-suggestions')
  @OpenAPI({ summary: 'Suggest hotels, wards, districts, and cities based on search query' })
  @ResponseSchema(SuggestHotelResponseDto)
  public async suggestHotels(@QueryParams() queryParams: SuggestHotelQueryParams, @Req() u: AuthorizedRequest) {
    return this.hotelService.getSearchSuggestions(queryParams, u.identity);
  }

  @Post('/search')
  @ResponseSchema(SearchHotelResponses)
  public async search(@Body() req: SearchHotelQueryParams, @Req() u: AuthorizedRequest) {
    return this.hotelService.search(req, u.identity);
  }

  @Get('')
  @OpenAPI({ summary: 'Get all hotels' })
  @ResponseSchema(HotelDto)
  public async getAllHotels(@QueryParams() queryParams: HotelQueryParams, @Req() u: AuthorizedRequest) {
    this.logger.info('getAllHotels:: Getting paginated hotels', queryParams);
    return this.hotelService.getHotels(queryParams, u.identity);
  }

  @Get('/:hotelId/rooms')
  @OpenAPI({ summary: 'Get rooms by hotel (paginated)' })
  @ResponseSchema(RoomsResponse)
  public async getRoomsByHotel(
    @Param('hotelId') id: number,
    @QueryParams() queryParams: BaseQueryParams,
    @Req() u: AuthorizedRequest,
  ) {
    this.logger.info('getRoomsByHotel:: Getting paginated rooms for hotel', { hotelId: id, queryParams });
    return this.hotelService.getRooms(id, { ...queryParams }, u.identity);
  }

  @Get('/:id')
  @OpenAPI({ summary: 'Get hotel by ID' })
  @ResponseSchema(HotelDto)
  public async getHotelById(@Param('id') id: number, @Req() u: AuthorizedRequest) {
    this.logger.info('getHotelById:: Getting hotel with ID:', id);
    return this.hotelService.getHotelById(id, u.identity);
  }
}

