import { Service } from 'typedi';
import { FindOptionsWhere } from 'typeorm';
import winston from 'winston';

import { Logger } from '@Decorators/Logger';

import { DEFAULT_AGENT_TITLE, env } from '@Libs/env';

import { BusinessLogicError } from '@Errors/BusinessLogicError';
import { ErrorCode } from '@Errors/ErrorCode';
import { NotFoundError } from '@Errors/NotFoundError';
import { BasicError } from '@Errors/BasicError';

import { Employee } from '@Entities/Employee';
import { HotelBooking } from '@Entities/HotelBooking';
import { HotelCommission } from '@Entities/HotelCommission';

import { EmployeeRepository } from '@Repositories/EmployeeRepository';

import { HotelBookingService } from '@Services/HotelBookingService';
import { HotelCommissionService } from '@Services/HotelCommissionService';
import { OrchIntegrationService } from '@Services/integration/OrchIntegrationService';
import { AmenityQueryParamInput } from '@Services/types/orchHotel/AmenityInput';
import { BookingQueryParamsInput } from '@Services/types/orchHotel/BookingInput';
import {
  HotelQueryParamsInput,
  SearchHotelQueryParamsInput,
  SuggestHotelQueryInput,
} from '@Services/types/orchHotel/HotelInput';
import {
  HotelPriceSearchParamsInput,
  HotelSearchSuggestionQueryInput,
} from '@Services/types/orchHotel/HotelSearchInput';
import { CreateRequestQuoteInput, RequestQuoteParamsInput } from '@Services/types/orchHotel/RequestQuoteInput';
import { RoomQueryParamsInput } from '@Services/types/orchHotel/RoomInput';
import { AgencyService } from '@Services/AgencyService';

import { AuthorizedRequest } from '@Rests/types/AuthorizedRequest';

@Service()
export class HotelService {
  constructor(
    @Logger(module) private readonly logger: winston.Logger,
    private readonly integrationService: OrchIntegrationService,
    private readonly hotelBookingService: HotelBookingService,
    private readonly hotelCommissionService: HotelCommissionService,
    private readonly agencyService: AgencyService,
    private readonly employeeRepo: EmployeeRepository,
  ) { }

  getHotels(params: HotelQueryParamsInput, identity: Employee) {
    return this.integrationService.getHotels(params);
  }

  getSearchSuggestions(params: SuggestHotelQueryInput, identity: Employee) {
    return this.integrationService.getSearchSuggestions(params);
  }

  search(params: SearchHotelQueryParamsInput, identity: Employee) {
    return this.integrationService.search(params);
  }

  getHotelById(id: number, identity: Employee) {
    return this.integrationService.getHotelById(id);
  }

  getRooms(hotelId: number, params: RoomQueryParamsInput, identity: Employee) {
    return this.integrationService.getRooms(hotelId, params);
  }

  getRoom(id: number, identity: Employee) {
    return this.integrationService.getRoom(id);
  }

  // amenities api
  getAmenities(queryParams: AmenityQueryParamInput, identity: Employee) {
    return this.integrationService.getAmenities(queryParams);
  }

  // GEO
  getCountry() {
    return this.integrationService.getCountry();
  }

  getCityByCountry(countryId: number) {
    return this.integrationService.getCityByCountry(countryId);
  }
  getDistrictByCity(cityId: number) {
    return this.integrationService.getDistrictByCity(cityId);
  }
  getWardByDistrict(districtId: number) {
    return this.integrationService.getWardByDistrict(districtId);
  }

  // Request Quote
  createRequestQuote(data: CreateRequestQuoteInput, identity: Employee) {
    return this.integrationService.createRequestQuote(data);
  }

  getRequestQuotes(params: RequestQuoteParamsInput, identity: Employee) {
    return this.integrationService.getRequestQuotes(params);
  }

  getRequestQuoteById(id: number, identity: Employee) {
    return this.integrationService.getRequestQuoteById(id);
  }

  // Booking
  async createBooking(data, identity: Employee) {
    data.ownerId = DEFAULT_AGENT_TITLE.toUpperCase();
    data.createdBy = identity.username;
    let agency = identity.agency;
    // check có phải f1 book không
    const isF1 = identity.agency.id === env.migration.agencyId;
    if (isF1 && data.agencyCode) {
      // f1 book hộ f2
      if (identity.agency.id !== env.migration.agencyId)
        throw new BasicError(ErrorCode.NO_PERMISSION_TO_ASSIGN_THIS_AGENCY);

      agency = await this.agencyService.findByCode(data.agencyCode);
      if (!agency)
        throw new BasicError(ErrorCode.AGENCY_NOT_FOUND);
      identity = await this.employeeRepo.findAdminByAgencyCode(agency.id, agency.agencyCode);
    }

    data.contact = {
      firstName: identity.firstName || 'Guest',
      lastName: identity.lastName || '',
      phone: identity.phoneNumber || identity.agency.ownerPhoneNumber,
      email: identity.emailAddress,
      agencyCode: agency.agencyCode,
      agencyPhone: agency.ownerPhoneNumber,
    };

    // Verify F2 commission từ FE
    await this.verifyF2Commission(data, identity);

    // Lưu lại commission F2 trước khi ghi đè bằng commissionFromSource (F1) để verify
    let savedF2CommissionTotal = 0;
    const f2RoomCommissions = new Map<number, number>();
    // Gửi commissionFromSource (giá trị gốc chưa apply F2) lên orchestrator để verify
    if (data.rooms?.length) {
      for (const room of data.rooms) {
        if (room.commissionFromSource !== undefined && room.commissionFromSource !== null) {
          const f2Comm = Number(room.commissionTotal) || 0;
          savedF2CommissionTotal += f2Comm;
          f2RoomCommissions.set(room.roomId, f2Comm);
          room.commissionTotal = room.commissionFromSource;
          room.agentCommission = f2Comm; // Lưu lại commission F2 vào trường riêng để sau này có thể tính toán nếu cần, tránh ghi đè lên commissionTotal đã gửi lên server để verify
        }
      }
    }
    const booking = await this.integrationService.createBooking(data);
    const totalPrice = Number(booking.netTotal) || 0;
    // Nếu có F2 commission đã lưu thì dùng, không thì dùng từ booking (F1)
    const totalCommissionAmount =
      savedF2CommissionTotal > 0 ? savedF2CommissionTotal : Number(booking.commissionTotal) || 0;
    // F2: tính lại totalPriceToBePaid theo F2 commission
    const totalPriceToBePaid =
      savedF2CommissionTotal > 0 ? totalPrice - savedF2CommissionTotal : Number(booking.agentToBePaidAmount) || 0;
    const hotel = booking.hotel;
    const bookingRooms = booking.bookingRooms.map(room => ({
      ...room,
      // F2: dùng commission F2 đã lưu, F1: giữ nguyên từ server
      commissionTotal: f2RoomCommissions.get(room.room?.id) ?? room.commissionTotal,
      condition: room.cancellation?.type,
      cancellationPeriod: room.cancellation?.time,
      cancellationPeriodUnitTime: room.cancellation?.unit,
      unitType: room.cancellation?.feeType,
      amount: room.cancellation?.cancellationFee,
    }));

    return this.hotelBookingService.create(
      {
        source: hotel?.source,
        code: booking.code ?? `${Date.now()}`,
        externalCode: booking.externalCode,
        totalPrice,
        totalPriceToBePaid,
        totalCommissionAmount,
        commissionFromSource: Number(booking.commissionTotal) || 0,
        totalCommissionRate: totalPrice > 0 ? (totalCommissionAmount / totalPrice) * 100 : 0,
        totalAmountPaid: 0,
        totalPriceRefund: 0,
        note: data.note,
        status: booking.status,
        title: data.title,
        hotel,
        bookingRooms,
        customerId: data.customerId,
        contactName: data.contactName,
        contactPhone: data.contactPhone,
        contactEmail: data.contactEmail,
        contactAddress: data.contactAddress,
        sendEmailToCustomer: data.sendEmailToCustomer,
        agencyCode: data.agencyCode,
        guest: booking.guest,
        agency: identity.agency,
        cancellation: booking.cancellation,
        checkInDate: booking.checkInDate,
        checkOutDate: booking.checkOutDate,
        raw: booking,
      },
      identity,
    );
  }

  getBookings(params: BookingQueryParamsInput, identity: Employee) {
    const isF1 = identity?.agency.id === env.migration.agencyId;
    if (!isF1) {
      params.agencyCodes = [identity.agency.agencyCode];
    }
    return this.hotelBookingService.findAllPaginated(params);
  }

  async getBooking(code: string, identity: Employee) {
    const isF1 = identity?.agency.id === env.migration.agencyId;
    const where: FindOptionsWhere<HotelBooking> = { code };
    if (!isF1) {
      where.agency = { agencyCode: identity.agency.agencyCode };
    }
    const item = await this.hotelBookingService.findOne({ where, relations: ['agency', 'createdBy'] });
    if (!item) throw new NotFoundError(ErrorCode.BOOKING_NOT_FOUND);
    let isLoadBookingFail = false;
    try {
      const bookingRes = await this.integrationService.getBooking(code);
      if (bookingRes) {
        // Lấy paidAt từ paymentHistories mới nhất
        const latestPayment = bookingRes.paymentHistories?.length
          ? bookingRes.paymentHistories[bookingRes.paymentHistories.length - 1]
          : null;
        const update: Partial<HotelBooking> = {
          externalCode: bookingRes.externalCode,
          paymentDeadline: bookingRes.paymentDeadline,
          status: bookingRes.status,
          totalAmountPaid: Number(bookingRes.agentPaidAmount || 0) +
            (Number(bookingRes.agentPaidAmount || 0) > 0 ?
              ((Number(item.commissionFromSource || 0) - Number(item.totalCommissionAmount || 0)) || 0) : 0),
          // Số tiền còn phải trả = netTotal - commission - đã thanh toán (luôn >= 0)
          totalPriceToBePaid: Math.max(0,
            Number(bookingRes.netTotal || 0) - Number(bookingRes.commissionTotal || 0)
            - Number(bookingRes.agentPaidAmount || 0)
            + (Number(bookingRes.agentPaidAmount) === 0
              ? ((Number(item.commissionFromSource || 0) - Number(item.totalCommissionAmount || 0)) || 0)
              : 0),
          ),
          ...(latestPayment?.paidAt ? { paymentAt: new Date(latestPayment.paidAt) } : {}),
          paymentHistories: bookingRes.paymentHistories || [],
          bookingRooms: bookingRes.bookingRooms.map(room => {
            // F2: giữ commissionTotal từ CMS DB, không ghi đè bằng F1 từ server
            const existingRoom = item.bookingRooms?.find(r => r.id === room.id);
            const commissionTotal =
              !isF1 && existingRoom?.commissionTotal != null ? existingRoom.commissionTotal : room.commissionTotal;
            return {
              ...room,
              commissionTotal,
              condition: room.cancellation?.type,
              cancellationPeriod: room.cancellation?.time,
