   * Đảm bảo FE luôn nhận được trường commissionFromSource bất kể F1 hay F2.
   */
  private setCommissionFromSource(response: any): void {
    for (const item of response.items) {
      for (const roomOption of item.roomOptions) {
        for (const mealPlanOption of roomOption.mealPlanOptions) {
          if (!mealPlanOption.cancellationOptions) continue;

          for (const cancellationOption of mealPlanOption.cancellationOptions) {
