      .findCommissionByAgency(
        identity.agency.id, { identity } as any,
      );
    const f2Percentage = f2Commission?.commissionAmount;
    if (!f2Percentage || f2Percentage <= 0) return;

    for (const room of data.rooms) {
      if (room.commissionFromSource == null) continue;

      const expectedF2 = this.calculateF2Commission(
        Number(room.commissionFromSource), f2Percentage,
      );
      const feF2 = Number(room.commissionTotal) || 0;

      if (Math.abs(expectedF2 - feF2) > 1) {
        this.logger.warn(
          'verifyF2Commission:: mismatch '
          + `roomId=${room.roomId}: `
          + `FE=${feF2}, expected=${expectedF2}`,
        );
        throw new BusinessLogicError(
          ErrorCode.HOTEL_COMMISSION_MISMATCH,
        );
      }
    }
  }
  // #endregion
}

