  async findAllPaginated(params: BookingQueryParamsInput): Promise<HttpPaginatedResponse<HotelBooking>> {
    const {
      page,
      size,
      searchText,
      sortBy = 'id',
      sortDirection = 'DESC',
      hotelName,
      title,
      status,
      checkInFrom,
      checkInTo,
      checkOutFrom,
      checkOutTo,
      bookedFrom,
      bookedTo,
      agencyCodes,
      code,
    } = params;
    const skip = (page - 1) * size;

    const qb = this.hotelBookingRepo
      .createQueryBuilder('entity')
      .leftJoinAndSelect('entity.agency', 'agency')
      .leftJoinAndSelect('entity.customer', 'customer')
      .leftJoinAndSelect('entity.createdBy', 'createdBy');

    if (searchText) {
      qb.andWhere('(entity.code ILIKE :search or entity.code ILIKE :search)', { search: `%${searchText}%` });
    }

    if (code) {
      qb.andWhere('entity.code ILIKE :code', { code });
    }

    if (agencyCodes && agencyCodes.length > 0) {
      qb.andWhere('agency.agencyCode IN (:...agencyCodes)', { agencyCodes });
    }

    if (hotelName) {
      qb.andWhere(
        'COALESCE(entity.hotel->>\'localName\', entity.hotel->0->>\'localName\') ILIKE :hotelName',
        { hotelName: `%${hotelName}%` },
      );
    }

    if (title) {
      qb.andWhere('entity.title ILIKE :title', { title: `%${title}%` });
    }

    if (status) {
      qb.andWhere('entity.status = :status', { status });
    }

    const checkInDateSql = `
      (
        SELECT MIN((stay->>'stayDate')::date)
        FROM jsonb_array_elements(COALESCE(entity.bookingRooms, '[]'::jsonb)) room
        LEFT JOIN LATERAL jsonb_array_elements(COALESCE(room->'stayDates', '[]'::jsonb)) stay ON true
      )
    `;

    const checkOutDateSql = `
      (
        SELECT MAX((stay->>'stayDate')::date)
        FROM jsonb_array_elements(COALESCE(entity.bookingRooms, '[]'::jsonb)) room
        LEFT JOIN LATERAL jsonb_array_elements(COALESCE(room->'stayDates', '[]'::jsonb)) stay ON true
      )
    `;

    if (checkInFrom) {
      qb.andWhere(`${checkInDateSql} >= :checkInFrom`, { checkInFrom });
    }

    if (checkInTo) {
      qb.andWhere(`${checkInDateSql} <= :checkInTo`, { checkInTo });
    }

    if (checkOutFrom) {
      qb.andWhere(`${checkOutDateSql} >= :checkOutFrom`, { checkOutFrom });
    }

    if (checkOutTo) {
      qb.andWhere(`${checkOutDateSql} <= :checkOutTo`, { checkOutTo });
    }

    if (bookedFrom && bookedTo) {
      qb.andWhere('entity.bookingDate BETWEEN :bookedFrom AND :bookedTo', {
        bookedFrom: moment(bookedFrom).startOf('day').subtract(7, 'hours')
          .toDate(),
        bookedTo: moment(bookedTo).endOf('day').subtract(7, 'hours')
          .toDate(),
      });
    } else if (bookedFrom) {
      qb.andWhere('entity.bookingDate >= :bookedFrom', {
        bookedFrom: moment(bookedFrom).startOf('day').subtract(7, 'hours')
          .toDate(),
      });
    } else if (bookedTo) {
      qb.andWhere('entity.bookingDate <= :bookedTo', {
        bookedTo: moment(bookedTo).endOf('day').subtract(7, 'hours')
          .toDate(),
      });
    }

    qb.orderBy(`entity.${sortBy}`, sortDirection as 'ASC' | 'DESC')
      .skip(skip)
      .take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<HotelBooking>()
      .withItems(items)
      .withTotal(total)
      .withPage(page)
      .withSize(size);
  }

