import { Service } from 'typedi';
import { DeepPartial, FindOneOptions } from 'typeorm';

import { HttpPaginatedResponse } from '@Libs/types/HttpPaginatedResponse';

import { BusinessLogicError } from '@Errors/BusinessLogicError';
import { ErrorCode } from '@Errors/ErrorCode';

import { HotelCommission } from '@Entities/HotelCommission';

import { HotelCommissionRepository } from '@Repositories/HotelCommissionRepository';
import { AgencyRepository } from '@Repositories/AgencyRepository';

import { AuthorizedRequest } from '@Rests/types/AuthorizedRequest';
import { CreateHotelCommissionDto, UpdateHotelCommissionDto } from '@Rests/types/HotelCommissionDto';

import { HotelCommissionQueryParamsInput } from './types/HotelCommissionInput';

@Service()
export class HotelCommissionService {
  constructor(private readonly hotelCommissionRepo: HotelCommissionRepository) { }

  async findAllPaginated(
    params: HotelCommissionQueryParamsInput,
    req: AuthorizedRequest,
  ): Promise<HttpPaginatedResponse<HotelCommission>> {
    const { page, size, searchText, sortBy, sortDirection } = params;
    const skip = (page - 1) * size;

    const qb = this.hotelCommissionRepo.createQueryBuilder('entity');

    qb.leftJoinAndSelect('entity.agency', 'agency');

    if (searchText) {
      qb.andWhere('entity.name ILIKE :search', { search: `%${searchText}%` });
    }

    qb.orderBy(`entity.${sortBy}`, sortDirection as 'ASC' | 'DESC')
      .skip(skip)
      .take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<HotelCommission>().withItems(items).withTotal(total)
      .withPage(page)
      .withSize(size);
  }

  findAll() {
    return this.hotelCommissionRepo.findAndCount();
  }

  findById(id: number) {
    return this.hotelCommissionRepo.findOne({
      where: { id },
      relations: ['agency'],
    });
  }

  async create(data: CreateHotelCommissionDto, req: AuthorizedRequest) {
    const targetAgencyId = data.agencyId ?? req.identity.agency.id;

    const existingCommission = await this.findCommissionByAgency(targetAgencyId, req);
    if (existingCommission) {
      throw new BusinessLogicError(ErrorCode.HOTEL_COMMISSION_AGENCY_DUPLICATE);
    }

    const { agencyId, ...commissionData } = data;
    const newCommission = {
      ...commissionData,
      agency: { id: targetAgencyId },
      createdBy: { id: req.identity.id },
    };

    return this.hotelCommissionRepo.insert(newCommission);
  }

  async update(id: number, data: UpdateHotelCommissionDto) {
    const updateData: DeepPartial<HotelCommission> = { ...data };
    await this.hotelCommissionRepo.updateById(id, updateData);
    return this.findById(id);
  }

  delete(id: number) {
    return this.hotelCommissionRepo.delete(id);
  }

  async findCommissionByAgency(agencyId: number, req: AuthorizedRequest) {
    const commission = await this.findActiveCommissionByAgencyId(agencyId);
    if (commission) {
      return commission;
    }

    const parentAgencyId = req.identity.agency?.parentAgency?.id;
    if (!parentAgencyId) {
      return null;
    }

    return this.findActiveCommissionByAgencyId(parentAgencyId);
  }

  private async findActiveCommissionByAgencyId(agencyId: number) {
    return this.hotelCommissionRepo.findOne({
      where: { agency: { id: agencyId }, isActive: true },
      relations: ['agency'],
    });
  }

  findOne(options: FindOneOptions<HotelCommission>) {
    return this.hotelCommissionRepo.findOne(options);
  }
}

