  }

  async multiPrices(data: HotelPriceSearchParamsInput, req: AuthorizedRequest) {
    const response = await this.integrationService.multiPrices(data);
    return this.applyF2CommissionIfNeeded(response, req);
  }

  private async applyF2CommissionIfNeeded(response: any, req: AuthorizedRequest) {
    // Luôn set commissionFromSource trước để FE luôn nhận field này
    // kể cả F1 hoặc F2 chưa cấu hình commission.
    this.setCommissionFromSource(response);

    const isF1 = req.identity?.agency.id === env.migration.agencyId;
    if (!isF1) {
      const agencyId = req.identity.agency.id;
      const f2Commission = await this.hotelCommissionService.findCommissionByAgency(agencyId, req);
      if (f2Commission) {
        this.applyF2Commission(response, f2Commission);
      }
    }
    return response;
  }

  private calculateF2Commission(
    commissionTotal: number,
    f2Percentage: number,
  ): number {
    if (commissionTotal === 0) return 0;
    return Math.round((commissionTotal * f2Percentage) / 100);
  }

  private applyF2Commission(response: any, commission: HotelCommission): void {
    const f2Percentage = commission.commissionAmount;

    for (const item of response.items) {
      for (const roomOption of item.roomOptions) {
        for (const mealPlanOption of roomOption.mealPlanOptions) {
          if (!mealPlanOption.cancellationOptions) continue;

          for (const cancellationOption of mealPlanOption.cancellationOptions) {
            const f2CommissionAmount = this.calculateF2Commission(
              cancellationOption.commissionTotal || 0,
              f2Percentage,
            );
            cancellationOption.commissionFromSource = cancellationOption.commissionTotal || 0;
            cancellationOption.commissionTotal = f2CommissionAmount;

            if (cancellationOption.stayDates?.length) {
              for (const stayDate of cancellationOption.stayDates) {
                const f2CommissionRate = this.calculateF2Commission(
                  stayDate.commissionRate || 0,
                  f2Percentage,
                );
                stayDate.commissionRate = f2CommissionRate;
              }
            }
          }
        }
      }
    }
  }

  /**
   * F1: set commissionFromSource = commissionTotal (không áp dụng F2).
   * Đảm bảo FE luôn nhận được trường commissionFromSource bất kể F1 hay F2.
   */
  private setCommissionFromSource(response: any): void {
    for (const item of response.items) {
      for (const roomOption of item.roomOptions) {
        for (const mealPlanOption of roomOption.mealPlanOptions) {
          if (!mealPlanOption.cancellationOptions) continue;

          for (const cancellationOption of mealPlanOption.cancellationOptions) {
            cancellationOption.commissionFromSource = cancellationOption.commissionTotal || 0;
          }
        }
      }
    }
  }

  /**
   * Verify F2 commission FE gửi lên có khớp với config trong DB.
   * Nếu sai lệch > 1 VND → throw HOTEL_COMMISSION_MISMATCH.
   */
  private async verifyF2Commission(
    data: any, identity: Employee,
  ): Promise<void> {
    const isF1 = identity.agency.id === env.migration.agencyId;
    if (isF1 || !data.rooms?.length) return;

    const f2Commission = await this.hotelCommissionService
      .findCommissionByAgency(
        identity.agency.id, { identity } as any,
      );
    const f2Percentage = f2Commission?.commissionAmount;
    if (!f2Percentage || f2Percentage <= 0) return;

    for (const room of data.rooms) {
      if (room.commissionFromSource == null) continue;

      const expectedF2 = this.calculateF2Commission(
        Number(room.commissionFromSource), f2Percentage,
      );
      const feF2 = Number(room.commissionTotal) || 0;

      if (Math.abs(expectedF2 - feF2) > 1) {
        this.logger.warn(
          'verifyF2Commission:: mismatch '
          + `roomId=${room.roomId}: `
          + `FE=${feF2}, expected=${expectedF2}`,
        );
        throw new BusinessLogicError(
          ErrorCode.HOTEL_COMMISSION_MISMATCH,
        );
      }
    }
  }

  /**
   * FE có thể đang gửi commission của F1 khi F1 book hộ F2.
   * Với case này backend chủ động tính lại commissionTotal theo config của agency đích.
   */
  private async syncBookingCommissionForTargetAgency(
    data: any,
    actorIdentity: Employee,
    bookingIdentity: Employee,
  ): Promise<void> {
    const isF1BookForF2 = actorIdentity.agency.id === env.migration.agencyId
      && !!data.agencyCode
      && bookingIdentity.agency.id !== env.migration.agencyId;

    if (!isF1BookForF2 || !data.rooms?.length) return;

    const f2Commission = await this.hotelCommissionService
      .findCommissionByAgency(
        bookingIdentity.agency.id,
        { identity: bookingIdentity } as any,
      );
    const f2Percentage = f2Commission?.commissionAmount;
    if (!f2Percentage || f2Percentage <= 0) return;

    for (const room of data.rooms) {
      const commissionFromSource = room.commissionFromSource ?? room.commissionTotal;
      if (commissionFromSource == null) continue;

      room.commissionFromSource = Number(commissionFromSource) || 0;
      room.commissionTotal = this.calculateF2Commission(
        room.commissionFromSource,
        f2Percentage,
      );
    }
  }
  // #endregion
}

